# C++ program to count the number of occurrences of a specific word in a text file

#include <iostream>
#include <fstream>
#include <string>
#include <regex>

using namespace std;

int main() {
  // Open the text file
  ifstream file("text.txt");

  // Check if the file is open
  if (!file) {
    cout << "Error opening file" << endl;
    return 1;
  }

  // Read the file line by line
  string line;
  while (getline(file, line)) {
    // Regular expression to match the word
    regex word("word");

    // Find all occurrences of the word in the line
    smatch match;
    if (regex_search(line, match, word)) {
      // Increment the count of occurrences
      count++;
    }
  }

  // Close the file
  file.close();

  // Print the count of occurrences
  cout << "Number of occurrences of the word: " << count << endl;

  return 0;
}
